    el.style.position='fixed';
    el.style.left=Math.max(0,Math.round(rect.left))+'px';
    el.style.right='auto';
    el.style.top=Math.max(0,Math.round(rect.top))+'px';
    el.style.bottom='auto';
    el.style.width=Math.max(1,Math.round(rect.width))+'px';
